1	// claim-office.ts
2	
3	type Step = { op: string; items: { type: string }[] };
4	
5	type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: Step[];
8	};
9	
10	type StepResult = { premium: number };
11	
12	type ScenarioResult = {
13	  results: StepResult[];
14	};
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	};
22	
23	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
24	const PROCESSING_FEE = 5;
25	
26	const quoteStep = (step: Step): StepResult => {
27	  const basePremium = step.items.reduce(
28	    (total, item) => total + BASE_PREMIUMS[item.type],
29	    0,
30	  );
31	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
32	  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
33	  return { premium };
34	};
35	
36	export const processScenario = (scenario: Scenario): ScenarioResult => ({
37	  results: scenario.steps.map(quoteStep),
38	});
